  9→import com.pinterest.ktlint.rule.engine.core.api.upsertWhitespaceAfterMe
 10→import com.pinterest.ktlint.rule.engine.core.api.upsertWhitespaceBeforeMe
 11→import com.pinterest.ktlint.ruleset.standard.StandardRule
 12→import org.jetbrains.kotlin.com.intellij.lang.ASTNode
 13→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
 14→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.PsiWhiteSpaceImpl
 15→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.TreeElement
 16→
 17→/**
 18→ * Lints and formats the spacing after the fun keyword
 19→ */
 20→public class FunctionStartOfBodySpacingRule : StandardRule("function-start-of-body-spacing") {
 21→    override fun beforeVisitChildNodes(
 22→        node: ASTNode,
 23→        autoCorrect: Boolean,
 24→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 25→    ) {
 26→        if (node.elementType == FUN) {
 27→            node
 28→                .findChildByType(ElementType.EQ)
 29→                ?.let { visitFunctionFollowedByBodyExpression(node, emit, autoCorrect) }
 30→
 31→            node
 32→                .findChildByType(ElementType.BLOCK)
 33→                ?.let { visitFunctionFollowedByBodyBlock(node, emit, autoCorrect) }
 34→        }
 35→    }
 36→
 37→    private fun visitFunctionFollowedByBodyExpression(
 38→        node: ASTNode,
 39→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 40→        autoCorrect: Boolean,
 41→    ) {
 42→        fixWhiteSpaceBeforeAssignmentOfBodyExpression(node, emit, autoCorrect)
 43→        fixWhiteSpaceBetweenAssignmentAndBodyExpression(node, emit, autoCorrect)
 44→    }
 45→
 46→    private fun fixWhiteSpaceBeforeAssignmentOfBodyExpression(
 47→        node: ASTNode,
 48→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 49→        autoCorrect: Boolean,
 50→    ) {
 51→        node
 52→            .findChildByType(ElementType.EQ)
 53→            ?.let { assignmentExpression ->
 54→                assignmentExpression
 55→                    .prevLeaf(includeEmpty = true)
 56→                    ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 57→                    .let { whiteSpaceBeforeAssignment ->
 58→                        if (whiteSpaceBeforeAssignment == null) {
 59→                            emit(
 60→                                assignmentExpression.startOffset,
 61→                                "Expected a single white space before assignment of expression body",
 62→                                true,
 63→                            )
 64→                            if (autoCorrect) {
 65→                                assignmentExpression.upsertWhitespaceBeforeMe(" ")
 66→                            }
 67→                        } else if (whiteSpaceBeforeAssignment.text != " ") {
 68→                            emit(whiteSpaceBeforeAssignment.startOffset, "Unexpected whitespace", true)
 69→                            if (autoCorrect) {
 70→                                assignmentExpression.upsertWhitespaceBeforeMe(" ")
 71→                            }
 72→                        }
 73→                    }
 74→            }
 75→    }
 76→
 77→    private fun fixWhiteSpaceBetweenAssignmentAndBodyExpression(
 78→        node: ASTNode,
 79→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 80→        autoCorrect: Boolean,
 81→    ) {
 82→        node
 83→            .findChildByType(ElementType.EQ)
 84→            ?.let { assignmentExpression ->
 85→                assignmentExpression
 86→                    .nextLeaf(includeEmpty = true)
 87→                    ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
 88→                    .let { whiteSpaceAfterAssignment ->
 89→                        if (!(whiteSpaceAfterAssignment?.text == " " || whiteSpaceAfterAssignment?.textContains('\n') == true)) {
 90→                            emit(
 91→                                assignmentExpression.startOffset,
 92→                                "Expected a single white space between assignment and expression body on same line",
 93→                                true,
 94→                            )
 95→                            if (autoCorrect) {
 96→                                assignmentExpression.upsertWhitespaceAfterMe(" ")
 97→                            }
 98→                        }
 99→                    }
100→            }
101→    }
102→
103→    private fun visitFunctionFollowedByBodyBlock(
104→        node: ASTNode,
105→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
106→        autoCorrect: Boolean,
107→    ) {
108→        node
109→            .findChildByType(ElementType.BLOCK)
110→            ?.let { block ->
111→                block
112→                    .prevLeaf(includeEmpty = true)
113→                    ?.takeIf { it.elementType == ElementType.WHITE_SPACE }
114→                    .let { whiteSpaceBeforeExpressionBlock ->
115→                        if (whiteSpaceBeforeExpressionBlock?.text != " ") {
116→                            emit(block.startOffset, "Expected a single white space before start of function body", true)
117→                            if (autoCorrect) {
118→                                block.upsertWhitespaceBeforeMeAtSameLevel(" ")
119→                            }
120→                        }
121→                    }
122→            }
123→    }
124→
125→    /**
126→     * Insert or update whitespace before [this] node at the same level (as a sibling of [this]).
127→     * This is different from [upsertWhitespaceBeforeMe] which may insert whitespace at a different
128→     * level in the AST if the node is the first child of its parent.
129→     */
130→    private fun ASTNode.upsertWhitespaceBeforeMeAtSameLevel(text: String) {
131→        val prevSibling = treePrev
132→        if (prevSibling != null && prevSibling.elementType == WHITE_SPACE) {
133→            // Replace existing whitespace sibling
134→            (prevSibling.psi as LeafElement).rawReplaceWithText(text)
135→        } else {
136→            // Insert new whitespace as a sibling of this node (at the same level)
137→            (treeParent as TreeElement).addChild(PsiWhiteSpaceImpl(text), this)
138→        }
139→    }
140→}
141→
142→public val FUNCTION_START_OF_BODY_SPACING_RULE_ID: RuleId = FunctionStartOfBodySpacingRule().ruleId
143→
